UPDATE `pest_and_disease` SET `ai_recommendation` = '{
  "diagnosis": "Ang inyong mga kape ay apektado ng Coffee Leaf Rust (Kalawang ng Kape), isang sakit na dulot ng fungus na *Hemileia vastatrix*. Dahil ito ay 'Severe' o matindi, nangangahulugan ito na maraming dahon ang may kalawang, nagiging dilaw, at nalalagas. Kung hindi ito agad maaagapan, lalong kakalat ang sakit, hihina ang inyong mga kape, bababa ang ani, at maaaring mamatay ang mga puno.",
  "urgency": "Critical",
  "urgency_reason": "Ang matinding pagkalat ng kalawang ay mabilis na magdudulot ng pagkalagas ng dahon, paghina ng puno, at malaking pagbaba ng ani kung hindi agad gagamutin.",
  "farmer_summary": "May matinding kalawang ang inyong mga kape, na mabilis na sumisira sa dahon at bunga. Kailangan nating kumilos agad para hindi tuluyang masira ang inyong ani at mga puno. Ang pinakamahalagang gawin ngayon ay alisin ang mga apektadong dahon at magsimulang mag-spray ng gamot.",
  "immediate_actions": [
    "Agad na putulin o alisin ang lahat ng dahon at sanga na may matinding kalawang. Kolektahin ang mga ito at ilibing nang malalim o sunugin malayo sa taniman para hindi kumalat ang spores.",
    "Kung mayroon kayong sabon panlaba o dishwashing liquid, ihalo ang 1 kutsara nito sa 1 litro ng tubig. I-spray ito sa mga apektadong dahon bilang pansamantalang panlinis at pampababa ng spores habang naghahanda ng mas epektibong gamot.",
    "Regular na suriin ang mga puno ng kape na hindi pa apektado. Kung may makitang kahit kaunting kalawang, agad itong alisin. Maaari ring i-spray ng dilute na sabon at tubig ang mga malulusog na puno bilang dagdag proteksyon."
  ],
  "treatment_protocol": [
    {
      "step": "Pagsasaayos at Paglilinis (Sanitation)",
      "detail": "Sa unang araw, tiyaking naalis at naitapon nang maayos ang lahat ng apektadong dahon at sanga. Ang paglilinis na ito ay mahalaga para mabawasan ang pinagmumulan ng sakit. Siguraduhing malinis ang paligid ng puno."
    },
    {
      "step": "Pag-spray ng Fungicide (Chemical Option)",
      "detail": "Gumamit ng copper-based fungicide tulad ng Kocide 101 (Copper Hydroxide) o Cupravit Forte (Copper Oxychloride). Sundin ang nakasaad sa etiketa, karaniwan ay 2-4 kutsara bawat 16 litro ng tubig. I-spray nang maigi ang ilalim at ibabaw ng dahon, lalo na sa mga bagong tubo. Mag-spray tuwing umaga o hapon, hindi sa tirik na araw."
    },
    {
      "step": "Pag-spray ng Fungicide (Organic Option)",
      "detail": "Bilang alternatibo, gumamit ng Bordeaux Mixture. Ihalo ang 1 kilo ng Copper Sulfate (Sulfato de Cobre) at 1 kilo ng Hydrated Lime (Apog) sa 100 litro ng tubig. Siguraduhing maayos ang paghahalo. I-spray nang maigi sa lahat ng bahagi ng puno, lalo na sa ilalim ng dahon. Maaari ding gumamit ng Neem Oil solution (50ml Neem Oil + 10ml dish soap sa 10L tubig)."
    },
    {
      "step": "Pagsuporta sa Halaman (Foliar Feeding)",
      "detail": "Pagkatapos ng unang spray ng fungicide (mga 3-5 araw), mag-spray ng foliar fertilizer na mayaman sa NPK at micronutrients. Makakatulong ito sa pagpapalakas ng puno at pagtubo ng bagong', `pest_and_disease`.`updated_at` = '2026-03-21 15:34:15' WHERE `case_id` = 9

